##  Part 3: Smallest Prime Factor Sieve

### When to Use?
- Prime factorization of multiple numbers
- Finding number of distinct prime factors
- GCD/LCM problems with factorization
- Divisor-related problems

### Why Normal Sieve Fails?
Normal sieve only tells us if a number is prime, not its prime factors. Factorizing each number from scratch takes O(√n) per number.

### Key Idea:
During sieving, store the smallest prime factor for each number. Then factorize any number in O(log n) time!

### Problem: Prime Factorization Queries

> Given Q queries with numbers up to N (N ≤ 10^6, Q ≤ 10^5), for each query number, return all its prime factors.
```cpp []
class Solution {
public:
    vector<int> spf; // Smallest Prime Factor
    
    void buildSPF(int n) {
        spf.resize(n + 1);
        for (int i = 0; i <= n; i++) spf[i] = i;
        
        for (int i = 2; i * i <= n; i++) {
            if (spf[i] == i) { // i is prime
                for (int j = i * i; j <= n; j += i) {
                    if (spf[j] == j) { // Not marked yet
                        spf[j] = i;
                    }
                }
            }
        }
    }
    
    vector<int> getPrimeFactors(int num) {
        vector<int> factors;
        while (num > 1) {
            factors.push_back(spf[num]);
            num /= spf[num];
        }
        return factors;
    }
    
    vector<vector<int>> primeFactorization(int n, vector<int>& queries) {
        buildSPF(n);
        vector<vector<int>> result;
        
        for (int q : queries) {
            result.push_back(getPrimeFactors(q));
        }
        return result;
    }
};
```
```python []
class Solution:
    def __init__(self):
        self.spf = []
    
    def buildSPF(self, n: int) -> None:
        self.spf = list(range(n + 1))
        
        for i in range(2, int(n**0.5) + 1):
            if self.spf[i] == i:  # i is prime
                for j in range(i * i, n + 1, i):
                    if self.spf[j] == j:  # Not marked yet
                        self.spf[j] = i
    
    def getPrimeFactors(self, num: int) -> List[int]:
        factors = []
        while num > 1:
            factors.append(self.spf[num])
            num //= self.spf[num]
        return factors
    
    def primeFactorization(self, n: int, queries: List[int]) -> List[List[int]]:
        self.buildSPF(n)
        result = []
        
        for q in queries:
            result.append(self.getPrimeFactors(q))
        
        return result
```
```java []
class Solution {
    int[] spf; // Smallest Prime Factor
    
    void buildSPF(int n) {
        spf = new int[n + 1];
        for (int i = 0; i <= n; i++) spf[i] = i;
        
        for (int i = 2; i * i <= n; i++) {
            if (spf[i] == i) { // i is prime
                for (int j = i * i; j <= n; j += i) {
                    if (spf[j] == j) { // Not marked yet
                        spf[j] = i;
                    }
                }
            }
        }
    }
    
    List<Integer> getPrimeFactors(int num) {
        List<Integer> factors = new ArrayList<>();
        while (num > 1) {
            factors.add(spf[num]);
            num /= spf[num];
        }
        return factors;
    }
    
    List<List<Integer>> primeFactorization(int n, int[] queries) {
        buildSPF(n);
        List<List<Integer>> result = new ArrayList<>();
        
        for (int q : queries) {
            result.add(getPrimeFactors(q));
        }
        return result;
    }
}
```





**Time Complexity:** 
- Build SPF: O(n log log n)
- Each query: O(log n)

**Space Complexity:** O(n)

